import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import Sidebar from './components/Sidebar';  // Importăm Sidebar
import Zoom from './components/Zoom';        // Importăm Zoom
import FileExplorer from './components/FileExplorer';
import MicrosoftTeams from './components/MicrosoftTeams';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/Chrome';

const App = () => {
  return (
    <Router>
      <div className="app-container">
        <Sidebar />  {/* Sidebar rămâne neschimbat */}
        <Switch>
          {/* Definește rutele pentru componente */}
          <Route exact path="/" component={FileExplorer} /> {/* Pagina principală */}
          <Route path="/zoom" component={Zoom} />
          <Route path="/teams" component={MicrosoftTeams} />
          <Route path="/word" component={MicrosoftWord} />
          <Route path="/excel" component={MicrosoftExcel} />
          <Route path="/powerpoint" component={PowerPoint} />
          <Route path="/pdf" component={PDFReader} />
          <Route path="/chrome" component={Chrome} />
        </Switch>
      </div>
    </Router>
  );
};

export default App;
